  | LEFT_PAREN
  | NOT
  | DIFFERS
  | EQUIVALES
  | FOLLOWS
  | IMPLIES
  | OR
  | AND
  | FALSE
  | TRUE
// This type is used to give symbolic names to token indexes, useful for error messages
type tokenId =
  | TOKEN_EOF
  | TOKEN_IDENT
  | TOKEN_MODULE
  | TOKEN_OPEN
  | TOKEN_TH
  | TOKEN_AX
