  | TOKEN_AND
  | TOKEN_FALSE
  | TOKEN_TRUE
  | TOKEN_end_of_input
  | TOKEN_error
// This type is used to give symbolic names to token indexes, useful for error messages
type nonTerminalId =
  | NONTERM__startstart
  | NONTERM_predicate
