// This function maps tokens to integer indexes
let tagOfToken (t: token) =
  match t with
  | EOF -> 0
  | IDENT _ -> 1
  | MODULE -> 2
  | OPEN -> 3
  | TH -> 4
  | AX -> 5
  | SQUARE -> 6
  | PROOF -> 7
  | COMMA -> 8
  | RIGHT_BRACE -> 9
  | LEFT_BRACE -> 10
  | RIGHT_PAREN -> 11
  | LEFT_PAREN -> 12
  | NOT -> 13
  | DIFFERS -> 14
  | EQUIVALES -> 15
  | FOLLOWS -> 16
  | IMPLIES -> 17
  | OR -> 18
  | AND -> 19
  | FALSE -> 20
  | TRUE -> 21

// This function maps integer indexes to symbolic token ids
let tokenTagToTokenId (tokenIdx: int) =
  match tokenIdx with
  | 0 -> TOKEN_EOF
  | 1 -> TOKEN_IDENT
  | 2 -> TOKEN_MODULE
  | 3 -> TOKEN_OPEN
  | 4 -> TOKEN_TH
  | 5 -> TOKEN_AX
  | 6 -> TOKEN_SQUARE
  | 7 -> TOKEN_PROOF
  | 8 -> TOKEN_COMMA
  | 9 -> TOKEN_RIGHT_BRACE
  | 10 -> TOKEN_LEFT_BRACE
  | 11 -> TOKEN_RIGHT_PAREN
  | 12 -> TOKEN_LEFT_PAREN
  | 13 -> TOKEN_NOT
  | 14 -> TOKEN_DIFFERS
  | 15 -> TOKEN_EQUIVALES
  | 16 -> TOKEN_FOLLOWS
  | 17 -> TOKEN_IMPLIES
  | 18 -> TOKEN_OR
  | 19 -> TOKEN_AND
  | 20 -> TOKEN_FALSE
  | 21 -> TOKEN_TRUE
  | 24 -> TOKEN_end_of_input
  | 22 -> TOKEN_error
  | _ -> failwith "tokenTagToTokenId: bad token"

